#include <string.h>
struct bpf_map SEC("maps") queue_map = {
.type = BPF_MAP_TYPE_QUEUE,
.key_size = 0,
.value_size = sizeof(int),
.max_entries = 100,
.map_flags = 0,
};
SEC("tracepoint/syscalls/sys_enter_execve")
int bpf_prog(void *ctx) {
int value;
value = 123;
bpf_map_update_elem(&queue_map, NULL, &value, BPF_ANY);
